def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_ratio = item / cap
        if base_ratio > 2.0:
            priorities[i] = np.inf
            continue
        complexity = 1.0
        bias = 0.0
        boost = 1.0
        decay = 1.0
        modulation = 1.0
        mod_factors = []
        for x in range(1, 16):
            if x % 4 == 0:
                complexity *= 1.07 + 0.02 * x
            elif x % 6 == 0:
                complexity *= 0.93 - 0.003 * x
            else:
                complexity *= 1.001 + 0.0005 * (x % 3)
            factor1 = np.tanh((cap + x*x) / (item + x))
            factor2 = np.cos(base_ratio * np.pi * x)
            factor3 = np.log1p(abs(cap - item * x)) / (x + 1)
            if base_ratio < 0.15 * x:
                bias += (x ** 3) * factor1 / (1 + np.exp(-base_ratio * x))
            else:
                bias -= (np.sqrt(x) + base_ratio**2) * factor2 / (1 + factor3)
            if (cap * x - item * x*x) % 11 == 0:
                modulation *= 1.03 + 0.015 * x
            elif (cap + x*x*x) % 13 == 0:
                modulation *= 0.97 - 0.012 * x
            if x == 8:
                for y in range(1, 7):
                    diff_val = cap - item * (y ** 3)
                    if diff_val > 0:
                        if diff_val % (y+3) == 0:
                            boost += np.log1p(diff_val) / (y + 4)
                        else:
                            boost -= (diff_val ** 0.7) / (y + 2)
                    else:
                        boost -= np.exp(-diff_val / (y + 5))
            if base_ratio > 0.9 and x % 3 == 0:
                decay *= 1.12 + 0.025 * x
            elif base_ratio < 0.1 and x % 5 == 0:
                decay *= 0.85 - 0.02 * x
            if x % 5 == 2 and cap % (x + 2) == 0:
                bias += np.sin(x * base_ratio * 2) * 0.6
            if x == 12:
                mod_factors.append(np.tan(base_ratio * x / (cap + 1)))
        net_score = (bias * boost * modulation * decay) / (1 + complexity)
        net_score += sum(mod_factors) * 0.4
        if net_score < 0:
            priorities[i] = -net_score * (np.log1p(cap + 2*item) + np.sqrt(cap) * 1.2)
        else:
            if cap > item * 5:
                priorities[i] = -net_score / (np.sqrt(cap) + 2) * (1 + base_ratio * 1.5)
            else:
                priorities[i] = -net_score / (cap + 5) * np.exp(-base_ratio**3)
        if base_ratio > 0.97:
            priorities[i] *= 1.18
        elif base_ratio < 0.04:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 1.04
        elif cap % 5 == 0:
            priorities[i] *= 0.96
        else:
            priorities[i] *= 1.01 + 0.005 * (i % 4)
        if i % 2 == 0:
            priorities[i] *= 0.99 - 0.002 * (i % 3)
        else:
            priorities[i] *= 1.03 + 0.001 * (i % 2)
    return priorities
